import{_ as r,c as n,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Über OpenCodeDocs: Eine Einführung | opencodedocs","description":"Erfahren Sie mehr über OpenCodeDocs, die erste Tutorial-Plattform im AI-Ökosystem. Wir analysieren Open-Source-Projekte tiefgehend und bieten qualitativ hochwertige, quellcode-gestützte Tutorials, die zu 100% lauffähig sind.","frontmatter":{"title":"Über OpenCodeDocs: Eine Einführung | opencodedocs","sidebarTitle":"Lernen Sie unsere Vision kennen","subtitle":"Über OpenCodeDocs: Eine Einführung | opencodedocs","description":"Erfahren Sie mehr über OpenCodeDocs, die erste Tutorial-Plattform im AI-Ökosystem. Wir analysieren Open-Source-Projekte tiefgehend und bieten qualitativ hochwertige, quellcode-gestützte Tutorials, die zu 100% lauffähig sind."},"headers":[],"relativePath":"de/about.md","filePath":"de/about.md"}'),o={name:"de/about.md"};function a(s,e,l,d,u,c){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="uber-opencodedocs" tabindex="-1">Über OpenCodeDocs <a class="header-anchor" href="#uber-opencodedocs" aria-label="Permalink to &quot;Über OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>Die erste Tutorial-Plattform im AI-Ökosystem · Quellcode-gestützt · 100% lauffähig</strong></p></blockquote><h2 id="unsere-vision" tabindex="-1">Unsere Vision <a class="header-anchor" href="#unsere-vision" aria-label="Permalink to &quot;Unsere Vision&quot;">​</a></h2><p>KI-Tools entwickeln sich rasant weiter, die offizielle Dokumentation hinkt hinterher, und Online-Tutorials sind veraltet – das alles wollen wir ändern.</p><p>OpenCodeDocs analysiert die Quellcode und offiziellen Beispiele von Open-Source-Projekten tiefgehend, extrahiert die Kernlogik und stellt durch automatisierte Verifizierung sicher, dass jede Codezeile tatsächlich ausgeführt werden kann.</p><p>Wenn sich ein Projekt aktualisiert, werden unsere Tutorials synchron aktualisiert. Jedes Tutorial ist klar mit der Git-Commit-Version gekennzeichnet, damit Sie wissen, auf welcher Version der Code basiert.</p><p><strong>Unser Ziel ist es, der &quot;Verified Standard&quot; im Bereich der KI-Tools zu werden.</strong></p><h2 id="open-source-lizenzen" tabindex="-1">Open-Source-Lizenzen <a class="header-anchor" href="#open-source-lizenzen" aria-label="Permalink to &quot;Open-Source-Lizenzen&quot;">​</a></h2><p>Wir glauben, dass Offenheit Vertrauen schafft. Wir freuen uns über Community-Beiträge, Korrekturen und Ergänzungen.</p><h3 id="tutorial-inhalte" tabindex="-1">Tutorial-Inhalte <a class="header-anchor" href="#tutorial-inhalte" aria-label="Permalink to &quot;Tutorial-Inhalte&quot;">​</a></h3><p><strong>Lizenz</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> Namensnennung - Nicht-kommerzielle Nutzung - Weitergabe unter gleichen Bedingungen. Die Wiedergabe und Anpassung ist erlaubt, jedoch muss die Quelle angegeben werden, sie darf nicht für kommerzielle Zwecke verwendet werden, und muss unter denselben Bedingungen geteilt werden.</p><h3 id="build-tool" tabindex="-1">Build-Tool <a class="header-anchor" href="#build-tool" aria-label="Permalink to &quot;Build-Tool&quot;">​</a></h3><p><strong>VitePress</strong>: Dieses Projekt wird mit <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> erstellt.<br> Vielen Dank an das VitePress-Team für den hervorragenden statischen Website-Generator.</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">GitHub-Repository ansehen</a></p><h2 id="kontaktieren-sie-uns" tabindex="-1">Kontaktieren Sie uns <a class="header-anchor" href="#kontaktieren-sie-uns" aria-label="Permalink to &quot;Kontaktieren Sie uns&quot;">​</a></h2><ul><li><strong>E-Mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const p=r(o,[["render",a]]);export{g as __pageData,p as default};
